from dataclasses import dataclass
from typing import List

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a politician into a readable sentence."""
    if not triples:
        return ""

    main_subject = triples[0].subject
    predicate_map = {}
    for t in triples:
        if t.predicate not in predicate_map:
            predicate_map[t.predicate] = []
        predicate_map[t.predicate].append(t.object)

    clauses = []

    # Main identity
    identity = main_subject
    if 'nationality' in predicate_map:
        identity = f"{main_subject}, a {predicate_map['nationality'][0]} politician"
    elif 'profession' in predicate_map:
        identity = f"{main_subject}, a {predicate_map['profession'][0]}"
    clauses.append(identity)

    # Birth info
    birth_clauses = []
    if 'birthDate' in predicate_map:
        birth_clauses.append(f"born on {predicate_map['birthDate'][0]}")
    elif 'birthYear' in predicate_map:
        birth_clauses.append(f"born in {predicate_map['birthYear'][0]}")
    if 'birthPlace' in predicate_map:
        birth_clauses.append(f"in {predicate_map['birthPlace'][0]}")
    if birth_clauses:
        clauses.append(f"who was {' '.join(birth_clauses)}")

    # Career info
    if 'office' in predicate_map:
        clauses.append(f"who served as {predicate_map['office'][0]}")
    if 'party' in predicate_map:
        clauses.append(f"with the {predicate_map['party'][0]} party")
    if 'country' in predicate_map:
        clauses.append(f"from {predicate_map['country'][0]}")
    if 'state' in predicate_map:
        clauses.append(f"in {predicate_map['state'][0]}")
    if 'region' in predicate_map:
        clauses.append(f"representing the {predicate_map['region'][0]} region")

    # Military info
    if 'militaryBranch' in predicate_map:
        clauses.append(f"and served in the {predicate_map['militaryBranch'][0]}")
    if 'militaryRank' in predicate_map:
        clauses.append(f"holding the rank of {predicate_map['militaryRank'][0]}")
    if 'battle' in predicate_map:
        clauses.append(f"and participated in the {predicate_map['battle'][0]}")
    if 'serviceStartYear' in predicate_map:
        clauses.append(f"starting service in {predicate_map['serviceStartYear'][0]}")
    if 'unit' in predicate_map:
        clauses.append(f"with {predicate_map['unit'][0]}")

    # Death info
    death_clauses = []
    if 'deathDate' in predicate_map:
        death_clauses.append(f"died on {predicate_map['deathDate'][0]}")
    elif 'deathYear' in predicate_map:
        death_clauses.append(f"died in {predicate_map['deathYear'][0]}")
    if 'deathPlace' in predicate_map:
        death_clauses.append(f"in {predicate_map['deathPlace'][0]}")
    if death_clauses:
        clauses.append(f"and {' '.join(death_clauses)}")

    # Education
    if 'almaMater' in predicate_map:
        clauses.append(f"and studied at {predicate_map['almaMater'][0]}")

    # Personal info
    if 'spouse' in predicate_map:
        clauses.append(f"and was married to {predicate_map['spouse'][0]}")
    if 'religion' in predicate_map:
        clauses.append(f"and was a {predicate_map['religion'][0]}")
    if 'residence' in predicate_map:
        clauses.append(f"with residence at {predicate_map['residence'][0]}")

    # Awards
    if 'award' in predicate_map:
        clauses.append(f"and received the {predicate_map['award'][0]}")

    # Career timeline
    if 'activeYearsStartDate' in predicate_map:
        clauses.append(f"starting in {predicate_map['activeYearsStartDate'][0]}")
    if 'activeYearsEndDate' in predicate_map:
        clauses.append(f"until {predicate_map['activeYearsEndDate'][0]}")

    # Office relationships
    if 'predecessor' in predicate_map:
        clauses.append(f"and was preceded by {predicate_map['predecessor'][0]}")
    if 'successor' in predicate_map:
        clauses.append(f"and was succeeded by {predicate_map['successor'][0]}")
    if 'hasDeputy' in predicate_map:
        clauses.append(f"with {predicate_map['hasDeputy'][0]} as deputy")

    # Office periods
    if 'inOfficeWhilePresident' in predicate_map:
        clauses.append(f"during the presidency of {predicate_map['inOfficeWhilePresident'][0]}")
    if 'inOfficeWhilePrimeMinister' in predicate_map:
        clauses.append(f"during the prime ministership of {predicate_map['inOfficeWhilePrimeMinister'][0]}")
    if 'inOfficeWhileVicePresident' in predicate_map:
        clauses.append(f"during the vice presidency of {predicate_map['inOfficeWhileVicePresident'][0]}")
    if 'inOfficeWhileGovernor' in predicate_map:
        clauses.append(f"during the governorship of {predicate_map['inOfficeWhileGovernor'][0]}")
    if 'inOfficeWhileMonarch' in predicate_map:
        clauses.append(f"during the reign of {predicate_map['inOfficeWhileMonarch'][0]}")

    # Combine all parts into one complex sentence
    result = clauses[0] + " " + ", ".join(clauses[1:]) if len(clauses) > 1 else clauses[0]

    return result + "."

# EVOLVE-BLOCK-END

